import axios from 'axios';

const api = axios.create({
  baseURL: process.env.REACT_APP_API_URL || 'http://localhost:5000/api',
  timeout: 15000,
});

// Attach JWT token to every request
api.interceptors.request.use((config) => {
  const token = localStorage.getItem('ws_token');
  if (token) config.headers.Authorization = `Bearer ${token}`;
  return config;
});

// Handle 401 globally — redirect to login
api.interceptors.response.use(
  (res) => res,
  (error) => {
    if (error.response?.status === 401) {
      localStorage.removeItem('ws_token');
      localStorage.removeItem('ws_user');
      window.location.href = '/login';
    }
    return Promise.reject(error);
  }
);

export default api;

// ─── Auth ──────────────────────────────────────────────────────────────────────
export const authApi = {
  register: (data) => api.post('/auth/register', data),
  login:    (data) => api.post('/auth/login', data),
  getMe:    ()     => api.get('/auth/me'),
  updateMe: (data) => api.put('/auth/me', data),
  changePassword: (data) => api.put('/auth/change-password', data),
};

// ─── Projects ─────────────────────────────────────────────────────────────────
export const projectsApi = {
  list:         (params) => api.get('/projects', { params }),
  get:          (id)     => api.get(`/projects/${id}`),
  create:       (data)   => api.post('/projects', data),
  update:       (id, data) => api.put(`/projects/${id}`, data),
  delete:       (id)     => api.delete(`/projects/${id}`),
  addMember:    (id, data) => api.post(`/projects/${id}/members`, data),
  updateMember: (id, userId, data) => api.put(`/projects/${id}/members/${userId}`, data),
  removeMember: (id, userId) => api.delete(`/projects/${id}/members/${userId}`),
};

// ─── Tasks ────────────────────────────────────────────────────────────────────
export const tasksApi = {
  list:         (projectId, params) => api.get(`/projects/${projectId}/tasks`, { params }),
  get:          (projectId, taskId) => api.get(`/projects/${projectId}/tasks/${taskId}`),
  create:       (projectId, data)   => api.post(`/projects/${projectId}/tasks`, data),
  update:       (projectId, taskId, data) => api.put(`/projects/${projectId}/tasks/${taskId}`, data),
  updateStatus: (projectId, taskId, status) => api.patch(`/projects/${projectId}/tasks/${taskId}/status`, { status }),
  delete:       (projectId, taskId) => api.delete(`/projects/${projectId}/tasks/${taskId}`),
};

// ─── Comments ─────────────────────────────────────────────────────────────────
export const commentsApi = {
  list:   (projectId, taskId)            => api.get(`/projects/${projectId}/tasks/${taskId}/comments`),
  create: (projectId, taskId, data)      => api.post(`/projects/${projectId}/tasks/${taskId}/comments`, data),
  update: (projectId, taskId, id, data)  => api.put(`/projects/${projectId}/tasks/${taskId}/comments/${id}`, data),
  delete: (projectId, taskId, id)        => api.delete(`/projects/${projectId}/tasks/${taskId}/comments/${id}`),
};

// ─── Reviews ──────────────────────────────────────────────────────────────────
export const reviewsApi = {
  list:   (projectId, taskId)              => api.get(`/projects/${projectId}/tasks/${taskId}/reviews`),
  submit: (projectId, taskId, data)        => api.post(`/projects/${projectId}/tasks/${taskId}/reviews/submit`, data),
  action: (projectId, taskId, reviewId, data) => api.post(`/projects/${projectId}/tasks/${taskId}/reviews/${reviewId}/action`, data),
};

// ─── Notifications ────────────────────────────────────────────────────────────
export const notificationsApi = {
  list:       (params) => api.get('/notifications', { params }),
  markRead:   (id)     => api.patch(`/notifications/${id}/read`),
  markAllRead: ()      => api.patch('/notifications/read-all'),
  delete:     (id)     => api.delete(`/notifications/${id}`),
};

// ─── Activity ─────────────────────────────────────────────────────────────────
export const activityApi = {
  list: (projectId, params) => api.get(`/projects/${projectId}/activity`, { params }),
};

// ─── Analytics ────────────────────────────────────────────────────────────────
export const analyticsApi = {
  overview:     (projectId) => api.get(`/projects/${projectId}/analytics/overview`),
  productivity: (projectId) => api.get(`/projects/${projectId}/analytics/productivity`),
  velocity:     (projectId) => api.get(`/projects/${projectId}/analytics/velocity`),
};

// ─── Attachments ──────────────────────────────────────────────────────────────
export const attachmentsApi = {
  list:   (projectId, taskId)       => api.get(`/projects/${projectId}/tasks/${taskId}/attachments`),
  upload: (projectId, taskId, form) => api.post(`/projects/${projectId}/tasks/${taskId}/attachments`, form, {
    headers: { 'Content-Type': 'multipart/form-data' },
  }),
  delete: (projectId, taskId, id)   => api.delete(`/projects/${projectId}/tasks/${taskId}/attachments/${id}`),
};

// ─── Users ────────────────────────────────────────────────────────────────────
export const usersApi = {
  search: (q) => api.get('/users/search', { params: { q } }),
};

// ─── AI ───────────────────────────────────────────────────────────────────────
export const aiApi = {
  suggestPriority:  (projectId, data) => api.post(`/projects/${projectId}/ai/suggest-priority`, data),
  suggestAssignee:  (projectId)       => api.get(`/projects/${projectId}/ai/suggest-assignee`),
  healthCheck:      (projectId)       => api.get(`/projects/${projectId}/ai/health-check`),
  taskBreakdown:    (projectId, taskId) => api.post(`/projects/${projectId}/ai/tasks/${taskId}/breakdown`),
};
